const recordId = $input.first().json.query?.id || '';
if (!recordId) throw new Error('record_id manquant');
return [{ json: { record_id: recordId } }];

const payload = $('⚙️ Préparer payload').first().json;
const dvfResp = $input.first().json;

// Récupère les comparables filtrés par type + surface
const comparables = (dvfResp.comparables || []).slice(0, 4);
const fourchette = dvfResp.fourchette || {};

// Utilise la fourchette DVF si Airtable n'en a pas
const prix_min = payload.prix_estime_min || fourchette.prix_estime_min || 0;
const prix_max = payload.prix_estime_max || fourchette.prix_estime_max || 0;
const prix_ret = payload.prix_retenu || fourchette.prix_retenu || 0;

return [{ json: {
  ...payload,
  comparables: comparables,
  prix_estime_min: prix_min,
  prix_estime_max: prix_max,
  prix_retenu: prix_ret,
  dvf_prix_m2_moyen: fourchette.prix_m2_moyen || 0,
}}];
